+
+    if (!yamlSeen && lineStart === 0 && line === '---') {
+      inYaml = true;
+      yamlSeen = true;
+      continue;
+    }
+    if (inYaml) {
+      if (line === '---' || line === '...') inYaml = false;
+      continue;
+    }
+
+    const fenceMatch = line.match(/^ {0,3}(`{3,}|~{3,})/);
+    if (fence) {
+      if (fenceMatch && fenceMatch[1][0] === fence.character && fenceMatch[1].length >= fence.length) fence = undefined;
+      continue;
+    }
+    if (fenceMatch) {
+      fence = {character: fenceMatch[1][0], length: fenceMatch[1].length};
+      continue;
+    }
+    if (/^\\s*\\$\\$\\s*$/.test(line)) {
+      inMath = !inMath;
+      continue;
+    }
+    if (inMath || lineStart >= start.start && lineStart < tocEnd) continue;
+
+    const match = line.match(headingRegex);
+    if (!match) continue;
+    const level = match[1].length;
+    if (level < options.minLevel || level > options.maxLevel) continue;
+
+    const parsed = parseHeading(match[2], options.useExplicitIds);
+    if (isExcluded(parsed.display, options.excludeHeadings)) continue;
+    const base = parsed.explicitId ?? makeAnchor(parsed.display);
+    const count = usedAnchors.get(base) ?? 0;
+    usedAnchors.set(base, count + 1);
+    headings.push({level, text: options.stripFormattingInToc ? stripFormatting(parsed.display) : parsed.display, anchor: count === 0 ? base : `${base}-${count}`});
+  }
+  return headings;
+}
+
+function parseHeading(text: string, useExplicitIds: boolean): {display: string, explicitId?: string} {
+  let value = text.replace(/[ \	]+#+[ \	]*$/, '').trim();
+  const explicit = value.match(/\\s*\\{#([^}\\s]+)\\}\\s*$/);
+  if (explicit) value = value.slice(0, explicit.index).trimEnd();
+  return {display: resolveLinksAndImages(value), explicitId: useExplicitIds ? explicit?.[1] : undefined};
+}
+
+function resolveLinksAndImages(text: string): string {
+  return text
+      .replace(/!\\[\\[[^\\]]*\\]\\]/g, '')
+      .replace(/!\\[[^\\]]*\\]\\([^)]*\\)/g, '')
+      .replace(/\\[\\[([^\\]]+)\\]\\]/g, (_, contents: string) => contents.split('|').at(-1) ?? '')
+      .replace(/\\[([^\\]]*)\\]\\([^)]*\\)/g, '$1')
+      .trim();
+}
+
+function stripFormatting(text: string): string {
+  return text
+      .replace(/<[^>]*>/g, '')
+      .replace(/(\\*\\*|__|~~|\\*|_|`)/g, '')
+      .replace(/\\\\(.)/g, '$1')
+      .trim();
+}
+
+function makeAnchor(text: string): string {
+  return stripFormatting(text)
+      .toLowerCase()
+      .replace(/\\s+/g, '-')
+      .replace(/[^a-z0-9-_]/g, '')
+      .replace(/-+/g, '-')
+      .replace(/^-+|-+$/g, '');
+}
+
+function isExcluded(heading: string, exclusions: string[]): boolean {
+  return exclusions.some((value) => {
+    const regex = value.match(/^\\/(.*)\\/$/);
+    if (regex) {
+      try {
+        return new RegExp(regex[1], 'i').test(heading);
+      } catch (_) {
+        return false;
+      }
+    }
+    return value.localeCompare(heading, undefined, {sensitivity: 'accent'}) === 0;
+  });
+}
+
+function renderToc(start: string, end: string, headings: Heading[], options: AutoTocOptions, newline: string): string {
+  const indentSize = Math.max(0, Number(options.indentSize) || 0);
+  const items = headings.map((heading, index) => {
+    const indent = ' '.repeat((heading.level - options.minLevel) * indentSize);
+    const marker = options.listStyle === 'number' ? `${options.orderedListStyle === 'increment' ? index + 1 : 1}.` : options.bulletMarker;
+    return `${indent}${marker} [${heading.text}](#${heading.anchor})`;
+  });
+  const body = [options.title, ...items].filter((line, index) => index !== 0 || line !== '').join(newline + newline);
+  return start + newline + newline + body + newline + newline + end + newline + newline;
