+import {Options, RuleType} from '../rules';
+import RuleBuilder, {BooleanOptionBuilder, DropdownOptionBuilder, ExampleBuilder, NumberOptionBuilder, OptionBuilderBase, TextAreaOptionBuilder, TextOptionBuilder} from './rule-builder';
+
+type ListStyle = 'bullet' | 'number';
+type OrderedListStyle = 'always-one' | 'increment';
+
+class AutoTocOptions implements Options {
+  listStyle?: ListStyle = 'bullet';
+  bulletMarker?: string = '-';
+  orderedListStyle?: OrderedListStyle = 'always-one';
+  indentSize?: Number = 2;
+  minLevel?: Number = 2;
+  maxLevel?: Number = 6;
+  title?: string = '';
+  useExplicitIds?: boolean = false;
+  stripFormattingInToc?: boolean = false;
+  excludeHeadings?: string[] = [];
+}
+
+type Marker = {start: number, end: number, text: string};
+type Heading = {level: number, text: string, anchor: string};
+
+const startMarkerRegex = /^[ \t]*<!--\s*toc\s*-->[ \t]*(?:\r?\n|$)/gim;
+const endMarkerRegex = /^[ \t]*<!--\s*\/toc\s*-->[ \t]*(?:\r?\n|$)/gim;
+const headingRegex = /^ {0,3}(#{1,6})[ \t]+(.+?)\s*$/;
+
+/** Generates a table of contents in an explicitly marked region. */
+@RuleBuilder.register
+export default class AutoToc extends RuleBuilder<AutoTocOptions> {
+  constructor() {
+    super({
+      nameKey: 'rules.auto-toc.name',
+      descriptionKey: 'rules.auto-toc.description',
+      type: RuleType.CONTENT,
+    });
+  }
+
+  get OptionsClass(): new () => AutoTocOptions {
+    return AutoTocOptions;
+  }
+
+  apply(text: string, options: AutoTocOptions): string {
+    const start = findMarker(startMarkerRegex, text, 0);
+    if (!start) {
+      return text;
+    }
+
+    const end = findMarker(endMarkerRegex, text, start.end);
+    const headings = findHeadings(text, start, end, options);
+    const newline = text.includes('\r\n') ? '\r\n' : '\n';
+    const toc = renderToc(start.text, end?.text ?? '<!-- /toc -->', headings, options, newline);
+    // Without an end marker, the following document content is not an existing
+    // TOC. Insert the generated region immediately after the start marker.
+    return text.slice(0, start.start) + toc + text.slice(end?.end ?? start.end);
+  }
+
+  get exampleBuilders(): ExampleBuilder<AutoTocOptions>[] {
+    return [
+      new ExampleBuilder({
+        description: 'Generates a table of contents inside TOC markers.',
+        before: '<!-- toc -->\n<!-- /toc -->\n## Heading',
+        after: '<!-- toc -->\n\n- [Heading](#heading)\n\n<!-- /toc -->\n\n## Heading',
+      }),
+    ];
+  }
+  get optionBuilders(): OptionBuilderBase<AutoTocOptions>[] {
